const raw = $json;

function tryParseJSON(str) {
  try {
    return JSON.parse(str);
  } catch {
    return null;
  }
}

function cleanText(str) {
  if (typeof str !== 'string') return '';
  return str
    .trim()
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/\s*```$/i, '')
    .trim();
}

function extractJsonSubstring(str) {
  if (typeof str !== 'string') return null;
  const start = str.indexOf('{');
  const end = str.lastIndexOf('}');
  if (start === -1 || end === -1 || end <= start) return null;
  return str.slice(start, end + 1);
}

function extractCandidate(obj) {
  if (!obj) return { parsed: null, source: 'empty' };

  if (typeof obj === 'object' && obj.action && obj.state_update) {
    return { parsed: obj, source: 'root_object' };
  }

  const content = obj?.choices?.[0]?.message?.content;

  if (typeof content === 'string') {
    const cleaned = cleanText(content);
    return {
      parsed: tryParseJSON(cleaned) || tryParseJSON(extractJsonSubstring(cleaned)),
      source: 'choices_message_content',
      raw_content: content
    };
  }

  if (typeof obj.output_text === 'string') {
    const cleaned = cleanText(obj.output_text);
    return {
      parsed: tryParseJSON(cleaned) || tryParseJSON(extractJsonSubstring(cleaned)),
      source: 'output_text',
      raw_content: obj.output_text
    };
  }

  if (Array.isArray(content)) {
    for (const part of content) {
      if (typeof part?.text === 'string') {
        const cleaned = cleanText(part.text);
        const parsed = tryParseJSON(cleaned) || tryParseJSON(extractJsonSubstring(cleaned));
        if (parsed) {
          return {
            parsed,
            source: 'content_array_text',
            raw_content: part.text
          };
        }
      }
    }
  }

  return { parsed: null, source: 'not_found' };
}

const result = extractCandidate(raw);

return [{
  json: {
    raw_response: raw,
    raw_content: result.raw_content || null,
    parsed_output: result.parsed,
    parse_ok: !!result.parsed,
    parse_source: result.source
  }
}];

const parsed = $json.parsed_output;
const prepared = $('prepare_context_and_guardrail').first().json;

const context = prepared.context_packet || {};
const allowedActions = prepared.allowed_actions || [];

const state = context.state || {};
const ruleContext = context.rule_context || {};
const conversation = context.conversation || {};

const errors = [];
const warnings = [];

const latestUserMessage = conversation.latest_user_message || '';

function isFilled(value) {
  if (value === null || value === undefined) return false;
  if (typeof value === 'string' && value.trim() === '') return false;
  if (Array.isArray(value) && value.length === 0) return false;
  return true;
}

function firstValue(...values) {
  for (const value of values) {
    if (isFilled(value)) return value;
  }
  return null;
}

function compactObject(obj) {
  const out = {};

  for (const [key, value] of Object.entries(obj || {})) {
    if (value === undefined) continue;
    if (value === null) continue;
    if (typeof value === 'string' && value.trim() === '') continue;
    out[key] = value;
  }

  return out;
}

if (!$json.schema_valid) {
  return [{
    json: {
      valid: false,
      validation_errors: $json.schema_errors || ['schema_invalid'],
      validation_warnings: [],
      decision: null,
      validation_meta: {
        allowed_actions: allowedActions,
        current_stage: state.stage || null,
        latest_user_message: latestUserMessage
      }
    }
  }];
}

if (!parsed || typeof parsed !== 'object') {
  return [{
    json: {
      valid: false,
      validation_errors: ['parsed_output_missing'],
      validation_warnings: [],
      decision: null,
      validation_meta: {
        allowed_actions: allowedActions,
        current_stage: state.stage || null,
        latest_user_message: latestUserMessage
      }
    }
  }];
}

const update = parsed.state_update || {};

const serviceInterest = firstValue(update.service_interest, state.service_interest);
const vehicleType = firstValue(update.vehicle_type, state.vehicle_type);
const district = firstValue(update.district, state.district);

const bookingDate = firstValue(
  update.booking_date,
  state.booking_date,
  ruleContext.booking_candidate?.booking_date
);

const bookingTime = firstValue(
  update.booking_time,
  state.booking_time,
  ruleContext.booking_candidate?.booking_time
);

const slotId = firstValue(
  update.slot_id,
  state.slot_id,
  ruleContext.booking_candidate?.slot_id,
  bookingDate && bookingTime ? `${bookingDate}_${bookingTime}` : null
);

const serviceAddress = firstValue(
  update.service_address,
  update.address,
  state.service_address,
  state.address,
  ruleContext.address_candidate?.address
);

const addressReference = firstValue(
  update.address_reference,
  state.address_reference,
  ruleContext.address_candidate?.address_reference
);

const addressConfirmed =
  update.address_confirmed === true ||
  state.address_confirmed === true;

const hasAddress =
  isFilled(serviceAddress) ||
  isFilled(addressReference) ||
  addressConfirmed;

const hasBookingContext =
  isFilled(state.pending_booking_slot) ||
  isFilled(state.booking_slot) ||
  isFilled(ruleContext.booking_candidate) ||
  isFilled(ruleContext.calendar_hold) ||
  (isFilled(bookingDate) && isFilled(bookingTime)) ||
  isFilled(slotId);

if (!allowedActions.includes(parsed.action)) {
  errors.push(`action_not_allowed:${parsed.action}`);
}

if (parsed.action === 'offer_available_slots') {
  if (!serviceInterest) errors.push('offer_available_slots_without_service_interest');
  if (!vehicleType) errors.push('offer_available_slots_without_vehicle_type');
  if (!district) errors.push('offer_available_slots_without_district');
}

if (parsed.action === 'send_quote') {
  if (!serviceInterest) errors.push('send_quote_without_service_interest');
  if (!vehicleType) errors.push('send_quote_without_vehicle_type');
  if (!district) errors.push('send_quote_without_district');
}

if (parsed.action === 'confirm_booking') {
  if (!serviceInterest) errors.push('confirm_booking_without_service_interest');
  if (!vehicleType) errors.push('confirm_booking_without_vehicle_type');
  if (!district) errors.push('confirm_booking_without_district');
  if (!bookingDate) errors.push('confirm_booking_without_booking_date');
  if (!bookingTime) errors.push('confirm_booking_without_booking_time');
  if (!hasBookingContext) errors.push('confirm_booking_without_booking_context');
  if (!hasAddress) errors.push('confirm_booking_without_address');
}

if (parsed.action === 'confirm_address') {
  const hasAddressCandidate =
    hasAddress ||
    isFilled(latestUserMessage);

  if (!hasAddressCandidate) {
    errors.push('confirm_address_without_address_candidate');
  }
}

if (parsed.action === 'collect_address') {
  const hasBookingCandidate =
    isFilled(bookingDate) ||
    isFilled(bookingTime) ||
    isFilled(slotId) ||
    Array.isArray(state.booking_options) && state.booking_options.length > 0;

  if (!hasBookingCandidate) {
    warnings.push('collect_address_without_booking_candidate');
  }
}

if (parsed.action === 'schedule_followup') {
  const followupType = firstValue(parsed.followup_type, update.followup_type, state.followup_type);
  const scheduledFor = firstValue(parsed.scheduled_for, update.scheduled_for, state.scheduled_for);

  if (!followupType) errors.push('schedule_followup_without_followup_type');
  if (!scheduledFor) errors.push('schedule_followup_without_scheduled_for');
}

if (parsed.action === 'handoff_human') {
  if (update.stage !== 'human_handoff') {
    warnings.push('handoff_without_human_handoff_stage');
  }
}

if (Number(parsed.confidence) < 0.45 && allowedActions.includes('handoff_human')) {
  warnings.push('low_confidence_recommend_handoff');
}

const normalizedStateUpdate = compactObject({
  ...(update || {}),

  slot_id: firstValue(update.slot_id, slotId),
  last_bot_action: firstValue(update.last_bot_action, parsed.action),

  missing_fields: Array.isArray(update.missing_fields)
    ? update.missing_fields
    : []
});

const normalizedDecision = {
  action: parsed.action,
  reason: String(parsed.reason || '').trim(),
  message: typeof parsed.message === 'string' ? parsed.message.trim() : '',
  state_update: normalizedStateUpdate,
  confidence: Number(parsed.confidence)
};

return [{
  json: {
    valid: errors.length === 0,
    validation_errors: errors,
    validation_warnings: warnings,
    decision: normalizedDecision,
    validation_meta: {
      allowed_actions: allowedActions,
      current_stage: state.stage || null,
      latest_user_message: latestUserMessage
    }
  }
}];

const validation = $json;
const prepared = $('prepare_context_and_guardrail').first().json;

const context = prepared.context_packet || {};
const allowed = prepared.allowed_actions || [];
const state = context.state || {};
const conversation = context.conversation || {};
const text = String(conversation.latest_user_message || '').toLowerCase();

function normalize(value) {
  return String(value || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();
}

function isFilled(value) {
  if (value === null || value === undefined) return false;
  if (typeof value === 'string' && value.trim() === '') return false;
  if (Array.isArray(value) && value.length === 0) return false;
  return true;
}

function looksLikeAddress(rawText) {
  const t = normalize(rawText);
  if (t.length < 8) return false;

  const hasNumber = /\d{2,6}/.test(t);
  const words = [
    'calle',
    'avenida',
    'av',
    'pasaje',
    'camino',
    'condominio',
    'depto',
    'departamento',
    'casa',
    'block',
    'torre',
    'villa',
    'pje',
    'edificio',
    'porton',
    'portón'
  ];

  return hasNumber || words.some(w => t.includes(normalize(w)));
}

function getAvailabilityConfig(rawText) {
  const t = normalize(rawText);

  if (
    t.includes('proxima semana') ||
    t.includes('siguiente semana') ||
    t.includes('la otra semana') ||
    t.includes('otra semana')
  ) {
    return {
      availability_window: 'next_week',
      availability_label: 'la próxima semana',
      days_ahead: 7,
      start_offset_days: 7,
      max_slots: 5
    };
  }

  if (
    t.includes('mas adelante') ||
    t.includes('mas horarios') ||
    t.includes('otros horarios') ||
    t.includes('otros dias') ||
    t.includes('otras semanas')
  ) {
    return {
      availability_window: 'next_14_days',
      availability_label: 'las próximas dos semanas',
      days_ahead: 14,
      start_offset_days: 0,
      max_slots: 6
    };
  }

  if (
    t.includes('este mes') ||
    t.includes('durante el mes')
  ) {
    return {
      availability_window: 'next_30_days',
      availability_label: 'las próximas semanas',
      days_ahead: 30,
      start_offset_days: 0,
      max_slots: 8
    };
  }

  return {
    availability_window: 'this_week',
    availability_label: 'los próximos días',
    days_ahead: 7,
    start_offset_days: 0,
    max_slots: 3
  };
}

const normalizedText = normalize(text);

const asksAvailability =
  normalizedText.includes('horario') ||
  normalizedText.includes('hora disponible') ||
  normalizedText.includes('disponible') ||
  normalizedText.includes('disponibilidad') ||
  normalizedText.includes('fecha') ||
  normalizedText.includes('agenda') ||
  normalizedText.includes('agendar') ||
  normalizedText.includes('proxima semana') ||
  normalizedText.includes('mas horarios') ||
  normalizedText.includes('otros dias');

const wantsCancel =
  normalizedText.includes('cancelar') ||
  normalizedText.includes('anular') ||
  normalizedText.includes('cancela') ||
  normalizedText.includes('no podre asistir') ||
  normalizedText.includes('no puedo asistir');

const wantsReschedule =
  normalizedText.includes('reagendar') ||
  normalizedText.includes('reprogramar') ||
  normalizedText.includes('cambiar la hora') ||
  normalizedText.includes('cambiar el horario') ||
  normalizedText.includes('otra hora') ||
  normalizedText.includes('otro dia') ||
  normalizedText.includes('no me sirve');

const waitingAddress =
  state.stage === 'collecting_address' ||
  state.next_goal === 'collect_address' ||
  state.last_bot_action === 'collect_address';

const hasBookingBasics =
  !!state.service_interest &&
  !!state.vehicle_type &&
  !!state.district;

const missingFields =
  Array.isArray(state.missing_fields)
    ? state.missing_fields
    : Array.isArray(context.context_hints?.priority_missing_fields)
      ? context.context_hints.priority_missing_fields
      : [];

let decision = null;

if (
  validation.validation_errors?.includes('confirm_booking_without_address') &&
  allowed.includes('collect_address')
) {
  decision = {
    action: 'collect_address',
    reason: 'Fallback seguro: el usuario confirmó horario, pero falta dirección exacta antes de reservar.',
    message: 'Perfecto. Antes de confirmar la reserva, ¿me puedes enviar la dirección exacta donde sería el servicio?',
    state_update: {
      stage: 'collecting_address',
      next_goal: 'collect_address',
      intent_last: 'booking_confirmed_address_missing',
      last_bot_action: 'collect_address',
      missing_fields: ['address']
    },
    confidence: 0.2
  };
}

if (!decision && waitingAddress && looksLikeAddress(text) && allowed.includes('confirm_address')) {
  decision = {
    action: 'confirm_address',
    reason: 'Fallback seguro: el usuario entregó una dirección mientras el bot estaba esperando dirección.',
    message: '',
    state_update: {
      stage: 'address_confirmation',
      next_goal: 'validate_address',
      intent_last: 'address_provided',
      service_address: conversation.latest_user_message,
      address: conversation.latest_user_message,
      address_reference: conversation.latest_user_message,
      address_confirmed: false,
      last_bot_action: 'confirm_address_in_progress',
      missing_fields: []
    },
    confidence: 0.2
  };
}

if (!decision && wantsCancel && allowed.includes('cancel_booking')) {
  decision = {
    action: 'cancel_booking',
    reason: 'Fallback seguro: el usuario pidió cancelar una reserva.',
    message: '',
    state_update: {
      stage: 'cancelling',
      next_goal: 'cancel_active_booking',
      intent_last: 'cancel_booking_requested',
      last_bot_action: 'cancel_booking_in_progress',
      missing_fields: []
    },
    confidence: 0.2
  };
}

if (!decision && wantsReschedule && allowed.includes('reschedule_booking')) {
  decision = {
    action: 'reschedule_booking',
    reason: 'Fallback seguro: el usuario pidió cambiar día u hora de su reserva.',
    message: '',
    state_update: {
      stage: 'reschedule',
      next_goal: 'collect_new_slot',
      intent_last: 'reschedule_booking_requested',
      last_bot_action: 'reschedule_booking_in_progress',
      missing_fields: []
    },
    confidence: 0.2
  };
}

if (!decision && asksAvailability && hasBookingBasics && allowed.includes('offer_available_slots')) {
  const availability = getAvailabilityConfig(text);

  decision = {
    action: 'offer_available_slots',
    reason: 'Fallback seguro: el usuario pidió disponibilidad y existen los datos mínimos para consultar horarios reales.',
    message: '',
    state_update: {
      stage: 'booking_selection',
      next_goal: 'send_available_slots',
      intent_last: 'availability_requested',
      ...availability,
      last_bot_action: 'offer_available_slots',
      missing_fields: []
    },
    confidence: 0.2
  };
}

if (!decision && missingFields.length > 0 && allowed.includes('ask_missing_data')) {
  const firstMissing = missingFields[0];

  let message = 'Perfecto. Para avanzar, necesito un dato más. ¿Me lo puedes indicar?';
  let nextGoal = 'collect_missing_data';

  if (firstMissing === 'district') {
    message = 'Perfecto. Para ayudarte bien, ¿en qué comuna estás?';
    nextGoal = 'collect_district';
  }

  if (firstMissing === 'vehicle_type') {
    message = 'Perfecto. Para cotizarte bien, ¿qué tipo de vehículo tienes?';
    nextGoal = 'collect_vehicle_type';
  }

  if (firstMissing === 'service_interest') {
    message = 'Claro. ¿Qué servicio te interesa exactamente?';
    nextGoal = 'collect_service_interest';
  }

  if (firstMissing === 'address') {
    message = 'Perfecto. Para dejar la reserva bien registrada, ¿me puedes enviar la dirección exacta donde sería el servicio?';
    nextGoal = 'collect_address';
  }

  decision = {
    action: 'ask_missing_data',
    reason: 'Fallback seguro orientado a recopilar el siguiente dato crítico.',
    message,
    state_update: {
      stage: state.stage || 'new_lead',
      next_goal: nextGoal,
      intent_last: state.intent_last || null,
      last_bot_action: 'ask_missing_data',
      missing_fields: missingFields
    },
    confidence: 0.2
  };
}

if (!decision && allowed.includes('answer_question')) {
  decision = {
    action: 'answer_question',
    reason: 'Fallback conservador para mantener conversación segura.',
    message: 'Gracias por tu mensaje. ¿Me puedes dar un poco más de detalle para responderte bien?',
    state_update: {
      stage: state.stage || null,
      next_goal: state.next_goal || null,
      intent_last: state.intent_last || null,
      last_bot_action: 'answer_question',
      missing_fields: missingFields
    },
    confidence: 0.2
  };
}

if (!decision && allowed.includes('handoff_human')) {
  decision = {
    action: 'handoff_human',
    reason: 'Fallback a humano por imposibilidad de validar una decisión segura.',
    message: 'Gracias por escribir. Voy a derivar tu caso para que te ayuden directamente.',
    state_update: {
      stage: 'human_handoff',
      next_goal: 'human_review',
      intent_last: 'handoff_required',
      human_handoff: true,
      last_bot_action: 'handoff_human',
      missing_fields: []
    },
    confidence: 0.2
  };
}

if (!decision) {
  decision = {
    action: allowed[0] || 'handoff_human',
    reason: 'Fallback final usando primera acción permitida.',
    message: '',
    state_update: {
      last_bot_action: allowed[0] || 'handoff_human',
      missing_fields: missingFields
    },
    confidence: 0.2
  };
}

return [{
  json: {
    valid: true,
    fallback_used: true,
    original_validation_errors: validation.validation_errors || [],
    original_validation_warnings: validation.validation_warnings || [],
    decision
  }
}];

const cp = $json.context_packet || {};

function trimString(value, max = 500) {
  if (typeof value !== 'string') return value;
  return value.length > max ? value.slice(0, max) : value;
}

function uniqueStrings(arr) {
  if (!Array.isArray(arr)) return [];
  return [...new Set(arr.filter(v => typeof v === 'string' && v.trim()))];
}

const sanitized = {
  lead: {
    ...(cp.lead || {}),
    id: cp.lead?.id || cp.state?.lead_id || null,
    phone: cp.lead?.phone || cp.lead?.external_id || null,
    channel: cp.lead?.channel || 'whatsapp'
  },

  state: {
    ...(cp.state || {}),
    lead_id: cp.state?.lead_id || cp.lead?.id || null,
    missing_fields: uniqueStrings(cp.state?.missing_fields)
  },

  conversation: {
    latest_user_message: trimString(cp.conversation?.latest_user_message || '', 500),
    short_summary: trimString(cp.conversation?.short_summary || '', 800),
    last_message_id: cp.conversation?.last_message_id || null,
    message_type: cp.conversation?.message_type || 'text'
  },

  business: cp.business || {},
  rule_context: cp.rule_context || {},
  context_hints: cp.context_hints || {},
  allowed_actions: uniqueStrings(cp.allowed_actions)
};

if (!sanitized.lead.id) {
  throw new Error('sanitize_context_packet missing lead.id');
}

if (!sanitized.lead.phone) {
  throw new Error('sanitize_context_packet missing lead.phone');
}

return [
  {
    json: {
      context_packet: sanitized
    }
  }
];

const parsed = $json.parsed_output;
const prepared = $('prepare_context_and_guardrail').first().json;
const allowedActions = prepared.allowed_actions || [];

const errors = [];

function isNonEmptyString(v) {
  return typeof v === 'string' && v.trim().length > 0;
}

function isObject(v) {
  return v && typeof v === 'object' && !Array.isArray(v);
}

if (!$json.parse_ok || !parsed) {
  errors.push('invalid_or_unparseable_output');
}

if (!isObject(parsed)) {
  errors.push('output_not_object');
}

if (parsed) {
  if (!isNonEmptyString(parsed.action)) errors.push('missing_action');
  else if (!allowedActions.includes(parsed.action)) errors.push('action_not_allowed');

  if (!isNonEmptyString(parsed.reason)) errors.push('missing_reason');

    const actionsThatCanBuildMessageLater = [
      'send_quote',
      'offer_available_slots',
      'confirm_booking',
      'send_service_menu',
      'recommend_service'
    ];

    if (
      !isNonEmptyString(parsed.message) &&
      !actionsThatCanBuildMessageLater.includes(parsed.action)
    ) {
      errors.push('missing_message');
    }
  if (!isObject(parsed.state_update)) {
    errors.push('missing_state_update');
  } else if (!Array.isArray(parsed.state_update.missing_fields)) {
    errors.push('missing_fields_must_be_array');
  }

  if (typeof parsed.confidence !== 'number' || Number.isNaN(parsed.confidence)) {
    errors.push('invalid_confidence');
  } else if (parsed.confidence < 0 || parsed.confidence > 1) {
    errors.push('confidence_out_of_range');
  }
}

return [{
  json: {
    parsed_output: parsed,
    schema_valid: errors.length === 0,
    schema_errors: errors,
    raw_response: $json.raw_response,
    raw_content: $json.raw_content,
    parse_source: $json.parse_source
  }
}];

const finalNode = $json;
const prepared = $('prepare_context_and_guardrail').first().json;
const parsedNode = $('parse_or_extract_structured_output').first().json;
const httpNode = $('HTTP Request').first().json;

const context = prepared.context_packet || {};
const lead = context.lead || {};
const state = context.state || {};
const conversation = context.conversation || {};

const usage = httpNode.usage || {};

const auditLog = {
  flow_name: 'llm_decision',
  lead_id: lead.id || lead.lead_id || lead.phone || lead.wa_id || null,
  channel: lead.channel || null,
  stage_before: state.stage || null,
  latest_user_message: conversation.latest_user_message || null,
  allowed_actions: prepared.allowed_actions || [],
  decision: finalNode.decision || null,
  meta: {
    fallback_used: finalNode.meta?.fallback_used || false,
    validation_errors: finalNode.meta?.validation_errors || [],
    validation_warnings: finalNode.meta?.validation_warnings || []
  },
  llm: {
    model: prepared.model_config?.model || null,
    parse_source: parsedNode.parse_source || null,
    raw_content: parsedNode.raw_content || null,
    prompt_tokens: usage.prompt_tokens || 0,
    completion_tokens: usage.completion_tokens || 0,
    total_tokens: usage.total_tokens || 0
  },
  created_at: new Date().toISOString()
};

return [{ json: auditLog }];

const finalDecisionNode = $('finalize_decision').first().json;
const preparedNode = $('prepare_context_and_guardrail').first().json;
const auditResult = $json;

const decision = finalDecisionNode.decision || null;
const contextPacket = preparedNode.context_packet || null;

if (!decision) {
  throw new Error('Missing decision in finalize_decision');
}

if (!contextPacket) {
